class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        def is_special(x):
            # Count of divisors excluding x itself
            count = 0
            for i in range(1, int(x**0.5) + 1):
                if x % i == 0:
                    if i != x:
                        count += 1
                    if x // i != i and x // i != x:
                        count += 1
            return count == 2

        count = 0
        for num in range(l, r + 1):
            if not is_special(num):
                count += 1
        return count
